/**
 * @fileoverview FloatingWindow component definition for JIT pipeline.
 *
 * @module module/FloatingWindow.def
 */

import razyui from '../index.js';
import { PART } from './FloatingWindow/constants.js';

/**
 * The definition object for the FloatingWindow component.
 * Contains configuration for tokens, states, templates, variants, and custom elements.
 *
 * @type {Object}
 */
export const FloatingWindowDef = {
    /**
     * The name of the component.
     * @type {string}
     */
    name: 'FloatingWindow',
    
    /**
     * The custom element tag name for the component.
     * @type {string}
     */
    tag: 'rui-floating-window',

    /**
     * Design tokens specific to the FloatingWindow component.
     * These tokens define the visual appearance of the component.
     */
    tokens: {
        prefix: 'fw',
        tokens: {
            'min-w':       { value: '220px',           description: 'Minimum width' },
            'min-h':       { value: '140px',           description: 'Minimum height' },
            'resize-hit':  { value: '6px',             description: 'Resize handle hit area' },
            'accent':      { ref: 'color.accent',      description: 'Accent color (snap guides)' },
        },
    },

    /**
     * State machine configuration for the FloatingWindow component.
     * Defines the possible states and transitions.
     */
    states: {
        initial: 'idle',
        states: {
            idle:      { on: { FOCUS: 'focused', DRAG_START: 'dragging', MINIMIZE: 'minimised' } },
            focused:   { on: { BLUR: 'idle', DRAG_START: 'dragging', MINIMIZE: 'minimised' } },
            dragging:  { on: { DRAG_END: 'focused' } },
            minimised: { on: { RESTORE: 'idle' } },
        },
        effects: {
            /**
             * Effect triggered when entering the 'focused' state.
             * Adds the 'fw-focused' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            focused(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('fw-focused');
            },
            /**
             * Effect triggered when exiting the 'focused' state.
             * Removes the 'fw-focused' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'focused:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('fw-focused');
            },
            /**
             * Effect triggered when entering the 'dragging' state.
             * Adds the 'fw-dragging' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            dragging(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('fw-dragging');
            },
            /**
             * Effect triggered when exiting the 'dragging' state.
             * Removes the 'fw-dragging' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'dragging:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('fw-dragging');
            },
            /**
             * Effect triggered when entering the 'minimised' state.
             * Adds the 'fw-minimised' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            minimised(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('fw-minimised');
            },
            /**
             * Effect triggered when exiting the 'minimised' state.
             * Removes the 'fw-minimised' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'minimised:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('fw-minimised');
            },
        },
    },

    /**
     * Template slot definitions for the FloatingWindow component.
     * Defines the HTML structure and classes for different parts of the component.
     */
    template: {
        slots: {
            root:    { element: 'div', classes: ['fw-window'] },
            header:  { element: 'div', classes: ['fw-header'] },
            title:   { element: 'span', classes: ['fw-title'] },
            body:    { element: 'div', classes: ['fw-body'] },
            btn:     { element: 'button', classes: ['fw-btn'] },
            resize:  { element: 'div', classes: ['fw-resize'] },
        },
    },

    /**
     * Variants configuration for the FloatingWindow component.
     * Defines different visual or behavioral variations.
     */
    variants: {
        snapped: { description: 'Snapped to edge' },
    },

    // ═══════════════════════════════════════
    //  JIT Parts
    // ═══════════════════════════════════════
    jitParts: {
        [PART.WINDOW]: PART.WINDOW,
        [PART.HEADER]: PART.HEADER,
        [PART.title]: PART.title,
        [PART.HEADER_BTNS]: PART.HEADER_BTNS,
        [PART.BTN]: PART.BTN,
        [PART.BODY]: PART.BODY,
        [PART.RESIZE]: PART.RESIZE,
        [PART.SNAP_OVERLAY]: PART.SNAP_OVERLAY,
        [PART.SNAP_PREVIEW]: PART.SNAP_PREVIEW,
        [PART.ATTACH_GUIDE]: PART.ATTACH_GUIDE,
        [PART.ATTACH_LINE]: PART.ATTACH_LINE,
    },

    styles: {},

    /**
     * Observed attributes for the custom element.
     * @type {string[]}
     */
    observedAttrs: ['title', 'width', 'height', 'closable', 'resizable'],
    
    /**
     * Mapping of observed attributes to component properties.
     * @type {Object<string, string>}
     */
    attrMap: {
        title: 'title',
        width: 'width',
        height: 'height',
        closable: 'closable',
        resizable: 'resizable',
    },
};

export default FloatingWindowDef;
