/**
 * @fileoverview FloatingWindow pure utility functions.
 * @module module/FloatingWindow/helpers
 */

import razyui from '../../index.js';
import { SNAP_EDGE, ATTACH_MAG } from './constants.js';

/**
 * Generate a unique window ID string.
 * @returns {string}
 */
export function generateId() {
    return 'fw-' + Math.random().toString(36).slice(2, 8);
}

/**
 * Create a button element.
 * @param {string} cls  — CSS class string
 * @param {string} text — button text content
 * @param {string} title — button title attribute
 * @returns {Elements}
 */
export function makeBtn(cls, html, title) {
    return razyui.el('button', { className: cls, innerHTML: html, title, type: 'button' });
}

/**
 * Detect edge-snap zone from cursor position.
 * @param {number} cx — cursor X
 * @param {number} cy — cursor Y
 * @returns {string|null} zone name or null
 */
export function detectEdgeSnap(cx, cy) {
    const T = SNAP_EDGE;
    const vw = window.innerWidth;
    const vh = window.innerHeight;

    // Corners → quadrants
    if (cx <= T && cy <= T) return 'tl';
    if (cx >= vw - T && cy <= T) return 'tr';
    if (cx <= T && cy >= vh - T) return 'bl';
    if (cx >= vw - T && cy >= vh - T) return 'br';

    // Edges → halves
    if (cx <= T) return 'left';
    if (cx >= vw - T) return 'right';
    if (cy <= T) return 'top';
    if (cy >= vh - T) return 'bottom';
    return null;
}

/**
 * Return { x, y, w, h } for a snap zone.
 * @param {string} zone
 * @returns {{ x: number, y: number, w: number, h: number }}
 */
export function snapRect(zone) {
    const vw = window.innerWidth, vh = window.innerHeight;
    const hw = vw / 2, hh = vh / 2;
    switch (zone) {
        case 'left':   return { x: 0, y: 0, w: hw, h: vh };
        case 'right':  return { x: hw, y: 0, w: hw, h: vh };
        case 'top':    return { x: 0, y: 0, w: vw, h: hh };
        case 'bottom': return { x: 0, y: hh, w: vw, h: hh };
        case 'full':   return { x: 0, y: 0, w: vw, h: vh };
        case 'tl':     return { x: 0, y: 0, w: hw, h: hh };
        case 'tr':     return { x: hw, y: 0, w: hw, h: hh };
        case 'bl':     return { x: 0, y: hh, w: hw, h: hh };
        case 'br':     return { x: hw, y: hh, w: hw, h: hh };
        default:       return { x: 0, y: 0, w: vw, h: vh };
    }
}

/**
 * Detect if a rect is close to any sibling rect edge (attach-snap).
 * Pure geometry — no DOM or instance access.
 *
 * @param {DOMRect} myRect      — this window's bounding rect
 * @param {DOMRect[]} otherRects — other windows' bounding rects
 * @param {number} magnetDist   — max pixel distance to trigger snap
 * @returns {object|null} best attach edge info or null
 */
export function findAttachEdge(myRect, otherRects, magnetDist) {
    let best = null;
    let bestDist = magnetDist + 1;

    for (let i = 0; i < otherRects.length; i++) {
        const them = otherRects[i];

        // Vertical overlap check
        const vOverlap = myRect.bottom > them.top + 8 && myRect.top < them.bottom - 8;
        // Horizontal overlap check
        const hOverlap = myRect.right > them.left + 8 && myRect.left < them.right - 8;

        if (vOverlap) {
            // my right edge → their left edge
            const dRL = Math.abs(myRect.right - them.left);
            if (dRL < bestDist) { bestDist = dRL; best = { side: 'right', targetIdx: i, dist: dRL, me: myRect, them }; }
            // my left edge → their right edge
            const dLR = Math.abs(myRect.left - them.right);
            if (dLR < bestDist) { bestDist = dLR; best = { side: 'left', targetIdx: i, dist: dLR, me: myRect, them }; }
        }
        if (hOverlap) {
            // my bottom → their top
            const dBT = Math.abs(myRect.bottom - them.top);
            if (dBT < bestDist) { bestDist = dBT; best = { side: 'bottom', targetIdx: i, dist: dBT, me: myRect, them }; }
            // my top → their bottom
            const dTB = Math.abs(myRect.top - them.bottom);
            if (dTB < bestDist) { bestDist = dTB; best = { side: 'top', targetIdx: i, dist: dTB, me: myRect, them }; }
        }
    }
    return best;
}
