/**
 * @fileoverview FloatingWindow component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, thresholds, defaults, instance registry
 *   helpers.js   — pure utility functions (snap geometry, button factory)
 *   state.js     — localStorage persistence
 *   view.js      — DOM setup/teardown + snap/attach visual feedback
 *   events.js    — centralised event binding with AbortController
 *
 * @module module/FloatingWindow
 */

import { default as razyui } from '../../index.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
import {
    instances, ATTACH_MAG, ATTACH_GAP,
    CLS, DEFAULTS,
} from './constants.js';
import {
    generateId, detectEdgeSnap, snapRect, findAttachEdge,
} from './helpers.js';
import { saveState, restoreState } from './state.js';
import {
    buildWindow, showSnapPreview, hideSnapPreview,
    showAttachGuide, hideAttachGuide, cleanupDOM,
} from './view.js';
import { bindDragEvents, bindResizeEvents } from './events.js';

/**
 * FloatingWindow — RazyUI v2
 *
 * Draggable, resizable floating window with snap-to-edge and snap-to-attach.
 *
 * Features:
 *   - Drag from title bar
 *   - Resize from edges / corners (8 handles)
 *   - Snap to viewport edges (left/right/top/bottom half, full-screen, quadrants)
 *   - Snap-to-attach: magnetically dock to other FloatingWindow instances
 *   - Double-click title bar → toggle full-screen snap
 *   - Minimise / maximise / close buttons
 *   - State persistence in localStorage
 *   - Stacking (z-index) management — click to bring to front
 *   - getControl() public API
 *
 * Usage:
 *   const win = new FloatingWindow('#container', {
 *       title: 'My Window',
 *       width: 400, height: 300,
 *       content: '<p>Hello world</p>',
 *   });
 *   const ctrl = win.getControl();
 *
 * @param {string|HTMLElement|null} target — parent element selector/ref, or null for document.body
 * @param {object} config
 * @param {string}  [config.title='Window']
 * @param {string|HTMLElement} [config.content='']
 * @param {number}  [config.width=400]
 * @param {number}  [config.height=300]
 * @param {number}  [config.x]  — initial left (auto if omitted)
 * @param {number}  [config.y]  — initial top  (auto if omitted)
 * @param {boolean} [config.resizable=true]
 * @param {boolean} [config.closable=true]
 * @param {boolean} [config.minimisable=true]
 * @param {boolean} [config.maximisable=true]
 * @param {boolean} [config.snap=true]           — edge snap
 * @param {boolean} [config.attachSnap=true]     — snap-to-attach to siblings
 * @param {string}  [config.storeKey]            — localStorage key for position persistence
 * @param {Function} [config.onClose]
 * @param {Function} [config.onMove]
 * @param {Function} [config.onResize]
 * @param {Function} [config.onSnap]
 */
const FloatingWindow = class {
    // ── Private fields ──
    #el = null;           // container (or body)
    #win = null;          // the .fw-window element
    #header = null;
    #titleEl = null;
    #body = null;
    #config = {};
    #eventAC = new AbortController();

    #pos = { x: DEFAULTS.posX, y: DEFAULTS.posY };
    #size = { w: DEFAULTS.width, h: DEFAULTS.height };
    #snapZone = null;     // 'left'|'right'|'top'|'bottom'|'full'|'tl'|'tr'|'bl'|'br'|null
    #freeRect = null;     // { x, y, w, h } saved before snap
    #snapOverlay = null;
    #attachGuide = null;
    #focused = false;
    #minimised = false;
    #closed = false;
    #hidden = true;
    #storeKey = null;
    #id = generateId();

    constructor(target, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve parent
        if (typeof target === 'string') target = razyui(target)[0];
        this.#el = target || document.body;

        this.#size.w = this.#config.width;
        this.#size.h = this.#config.height;
        this.#storeKey = this.#config.storeKey || null;

        this.#init();
        instances.add(this);
    }

    // ── Initialisation ───────────────────────────────────

    #init() {
        // 1. Build DOM
        const { win, header, titleEl, body, overlay, guide, btnRefs } =
            buildWindow(this.#config, this.#id, this.#pos, this.#size);

        this.#win = win;
        this.#header = header;
        this.#titleEl = titleEl;
        this.#body = body;
        this.#snapOverlay = overlay;
        this.#attachGuide = guide;

        // 2. Button events
        const sigOpts = { signal: this.#eventAC.signal };
        if (btnRefs.min)   razyui(btnRefs.min).on('click', () => this.#toggleMin(), sigOpts);
        if (btnRefs.max)   razyui(btnRefs.max).on('click', () => {
            if (this.#snapZone === 'full') this.#unsnap(window.innerWidth / 2, window.innerHeight / 2);
            else this.#snapTo('full');
        }, sigOpts);
        if (btnRefs.close) razyui(btnRefs.close).on('click', () => this.close(), sigOpts);

        // 3. Focus on click
        razyui(win).on('mousedown', () => this.#focus(), sigOpts);

        // 4. Escape to close
        if (this.#config.closable) {
            win[0].setAttribute('tabindex', '-1');
            win[0].addEventListener('keydown', (e) => {
                if (e.key === 'Escape') this.close();
            }, sigOpts);
        }

        // 4. Restore persisted state
        this.#restoreState();

        // 5. Drag events
        const dragCtx = {
            getWin:              () => this.#win,
            getPos:              () => ({ ...this.#pos }),
            setPos:              (x, y) => { this.#pos.x = x; this.#pos.y = y; },
            applyPosition:       (x, y) => { this.#win.css({ left: x + 'px', top: y + 'px' }); },
            getSnapZone:         () => this.#snapZone,
            isSnapEnabled:       () => this.#config.snap,
            isAttachSnapEnabled: () => this.#config.attachSnap,
            detectEdgeSnap:      (cx, cy) => detectEdgeSnap(cx, cy),
            detectAttachSnap:    () => this.#detectAttachSnap(),
            showSnapPreview:     (zone) => showSnapPreview(this.#snapOverlay, zone),
            hideSnapPreview:     () => hideSnapPreview(this.#snapOverlay),
            showAttachGuide:     (edge) => showAttachGuide(this.#attachGuide, edge),
            hideAttachGuide:     () => hideAttachGuide(this.#attachGuide),
            previewAttach:       (edge) => this.#previewAttach(edge),
            unsnap:              (cx, cy) => this.#unsnap(cx, cy),
            snapTo:              (zone) => this.#snapTo(zone),
            applyAttach:         (edge) => this.#applyAttach(edge),
            saveState:           () => this.#saveState(),
            onMove:              () => this.#config.onMove?.({ x: this.#pos.x, y: this.#pos.y }),
        };
        bindDragEvents(this.#header, dragCtx, this.#eventAC.signal);

        // 6. Resize events
        if (this.#config.resizable) {
            const resizeCtx = {
                setPos:    (x, y) => { this.#pos.x = x; this.#pos.y = y; },
                setSize:   (w, h) => { this.#size.w = w; this.#size.h = h; },
                saveState: () => this.#saveState(),
                onResize:  (w, h) => this.#config.onResize?.({ width: w, height: h }),
            };
            bindResizeEvents(this.#win, resizeCtx, this.#eventAC.signal);
        }

        // 7. Start hidden — call show() to reveal
        this.#win.css('display', 'none');
        this.#hidden = true;

        // 8. Focus (will apply when shown)
        this.#focus();
    }

    // ── Focus / z-index management ───────────────────────

    #focus() {
        if (this.#focused) return;
        // Blur all others
        for (const inst of instances) {
            if (inst !== this) inst.#blur();
        }
        zIndexRegistry.raise(this.#win[0]);
        this.#win.addClass(CLS.FOCUSED);
        this.#focused = true;
    }

    #blur() {
        this.#win?.removeClass(CLS.FOCUSED);
        this.#focused = false;
    }

    // ── Snap ─────────────────────────────────────────────

    #snapTo(zone) {
        if (this.#minimised) this.#toggleMin();
        // Save free rect before first snap
        if (!this.#snapZone) {
            this.#freeRect = {
                x: this.#pos.x, y: this.#pos.y,
                w: this.#win[0].offsetWidth, h: this.#win[0].offsetHeight,
            };
        }
        this.#snapZone = zone;
        this.#win.addClass(CLS.SNAPPED);

        const r = snapRect(zone);
        this.#win.css({ left: r.x + 'px', top: r.y + 'px', width: r.w + 'px', height: r.h + 'px' });
        this.#pos.x = r.x; this.#pos.y = r.y;
        this.#size.w = r.w; this.#size.h = r.h;

        this.#saveState();
        this.#config.onSnap?.(zone);
    }

    #unsnap(cx, cy) {
        const fr = this.#freeRect || { x: DEFAULTS.posX, y: DEFAULTS.posY, w: this.#config.width, h: this.#config.height };
        this.#snapZone = null;
        this.#win.removeClass(CLS.SNAPPED);

        this.#win.css({ width: fr.w + 'px', height: fr.h + 'px' });

        // Centre around cursor
        const x = Math.max(0, Math.min(window.innerWidth - fr.w, cx - fr.w / 2));
        const y = Math.max(0, Math.min(window.innerHeight - DEFAULTS.fallbackTop, cy - DEFAULTS.restoreYOff));
        this.#pos = { x, y };
        this.#size = { w: fr.w, h: fr.h };
        this.#win.css({ left: x + 'px', top: y + 'px' });
        this.#freeRect = null;
        this.#saveState();
    }

    // ── Attach-snap (dock to siblings) ───────────────────

    /** Detect if this window's current rect is close to another window edge. */
    #detectAttachSnap() {
        const myRect = this.#win[0].getBoundingClientRect();
        const otherRects = [];
        for (const other of instances) {
            if (other === this || other.#closed || other.#minimised) continue;
            otherRects.push(other.#win[0].getBoundingClientRect());
        }
        return findAttachEdge(myRect, otherRects, ATTACH_MAG);
    }

    /**
     * Compute the attach-snapped position for one axis and apply it
     * visually WITHOUT saving state (used during drag preview).
     */
    #previewAttach(edge) {
        const snapped = this.#calcAttachPos(edge);
        this.#win.css({ left: snapped.x + 'px', top: snapped.y + 'px' });
    }

    /** Snap-move this window so its edge exactly meets the target window. */
    #applyAttach(edge) {
        const snapped = this.#calcAttachPos(edge);
        this.#pos.x = snapped.x;
        this.#pos.y = snapped.y;
        this.#win.css({ left: this.#pos.x + 'px', top: this.#pos.y + 'px' });
        this.#saveState();
    }

    /** Return the { x, y } position after snapping to the given attach edge. */
    #calcAttachPos(edge) {
        const them = edge.them;
        let x = this.#pos.x, y = this.#pos.y;
        switch (edge.side) {
            case 'right':  x = them.left - this.#win[0].offsetWidth - ATTACH_GAP; break;
            case 'left':   x = them.right + ATTACH_GAP; break;
            case 'bottom': y = them.top - this.#win[0].offsetHeight - ATTACH_GAP; break;
            case 'top':    y = them.bottom + ATTACH_GAP; break;
        }
        return { x, y };
    }

    // ── Minimise toggle ──────────────────────────────────────────

    #toggleMin() {
        this.#minimised = !this.#minimised;
        this.#win.toggleClass(CLS.MINIMISED, this.#minimised);
        if (this.#minimised && this.#snapZone) {
            this.#unsnap(this.#pos.x + this.#size.w / 2, this.#pos.y + DEFAULTS.unsnapYOff);
        }
    }

    // ── State persistence ────────────────────────────────

    #saveState() {
        saveState(this.#storeKey, this.#pos, this.#size, this.#snapZone, this.#freeRect);
    }

    #restoreState() {
        const saved = restoreState(this.#storeKey);
        if (!saved) return;

        if (saved.snap) {
            if (saved.fr) this.#freeRect = saved.fr;
            this.#snapTo(saved.snap);
            return;
        }
        this.#pos = { x: saved.x, y: saved.y };
        this.#size = { w: saved.w || this.#config.width, h: saved.h || this.#config.height };
        this.#win.css({ left: saved.x + 'px', top: saved.y + 'px' });
        if (saved.w) this.#win.css('width', saved.w + 'px');
        if (saved.h) this.#win.css('height', saved.h + 'px');
    }

    // ── Public API ───────────────────────────────────────

    /** Close and destroy the window */
    close() {
        if (this.#closed) return;
        this.#closed = true;
        this.#eventAC?.abort();
        instances.delete(this);
        zIndexRegistry.release(this.#win[0]);
        cleanupDOM(this.#win, this.#snapOverlay, this.#attachGuide);
        this.#win = null;
        this.#config.onClose?.();
    }

    /** Show the window */
    show() {
        if (this.#closed || !this.#hidden) return;
        this.#hidden = false;
        this.#win.css('display', '');
        this.#focus();
    }

    /** Hide the window (without destroying) */
    hide() {
        if (this.#closed || this.#hidden) return;
        this.#hidden = true;
        this.#win.css('display', 'none');
    }

    /** Toggle visibility */
    toggle() {
        if (this.#hidden) this.show();
        else this.hide();
    }

    /** Alias for close() — full teardown. */
    destroy() {
        this.close();
    }

    /** Set window title */
    setTitle(text) {
        if (this.#titleEl) this.#titleEl.text(text);
    }

    /** Set body content */
    setContent(content) {
        if (!this.#body) return;
        if (typeof content === 'string') this.#body.html(content);
        else if (content instanceof HTMLElement) { this.#body.html('').append(content); }
    }

    /** Move window to position */
    moveTo(x, y) {
        if (this.#snapZone) this.#unsnap(x, y);
        this.#pos = { x, y };
        this.#win.css({ left: x + 'px', top: y + 'px' });
        this.#saveState();
    }

    /** Resize window */
    resizeTo(w, h) {
        if (this.#snapZone) this.#unsnap(this.#pos.x + w / 2, this.#pos.y + DEFAULTS.unsnapYOff);
        this.#size = { w, h };
        this.#win.css({ width: w + 'px', height: h + 'px' });
        this.#saveState();
    }

    /** Snap to a zone programmatically */
    snap(zone) {
        this.#snapTo(zone);
    }

    /** Bring to front */
    focus() {
        this.#focus();
    }

    /** Get the window DOM element */
    get element() { return this.#win; }
    /** Get the body DOM element */
    get body() { return this.#body; }
    /** Get current position */
    get position() { return { ...this.#pos }; }
    /** Whether the window is snapped */
    get snapped() { return this.#snapZone; }
    /** Whether closed */
    get closed() { return this.#closed; }

    /**
     * Return a lightweight control handle.
     */
    getControl() {
        const self = this;
        return {
            close:     ()          => self.close(),
            show:      ()          => self.show(),
            hide:      ()          => self.hide(),
            toggle:    ()          => self.toggle(),
            setTitle:  (t)         => self.setTitle(t),
            setContent:(c)         => self.setContent(c),
            moveTo:    (x, y)      => self.moveTo(x, y),
            resizeTo:  (w, h)      => self.resizeTo(w, h),
            snap:      (zone)      => self.snap(zone),
            focus:     ()          => self.focus(),
            get element()          { return self.element; },
            get body()             { return self.body; },
            get position()         { return self.position; },
            get snapped()          { return self.snapped; },
            get closed()           { return self.closed; },
            destroy:               () => self.destroy(),
        };
    }

    /** Static: close all open FloatingWindows */
    static closeAll() {
        for (const inst of [...instances]) inst.close();
    }
};

export default FloatingWindow;
